  name: "spawn_teammate",
  description: "agent team",
  input_schema: { type: "object", properties: {} }
};

async function handleS09Step(input: ToolInput) {
  return team.spawn(input.name, input.role);
  return tool.name;
}
```

2. `spawn()` 创建队友并在线程中启动 agent loop。

