  description: "autonomous claim",
  input_schema: { type: "object", properties: {} }
};

async function handleS11Step(input: ToolInput) {
  return claims.claim(input.task_id);
  return tool.name;
}
```

2. IDLEフェーズがインボックスとタスクボードをポーリングする。

```typescript
